import{_ as r,y as i,a as p,o as l,a2 as o,D as n,g as s,I as a}from"./chunks/framework.DCcmcJcL.js";const y=JSON.parse('{"title":"Role Based Permissions","description":"","frontmatter":{},"headers":[],"relativePath":"b2b-ecommerce-platform/role-based-permissions.md","filePath":"b2b-ecommerce-platform/role-based-permissions.md","lastUpdated":1782311298000}'),m={name:"b2b-ecommerce-platform/role-based-permissions.md"};function c(g,e,d,h,u,f){const t=i("ImagePopup");return l(),p("div",null,[e[0]||(e[0]=o('<h1 id="role-based-permissions" tabindex="-1">Role Based Permissions <a class="header-anchor" href="#role-based-permissions" aria-label="Permalink to &quot;Role Based Permissions&quot;">​</a></h1><p>The Role-Based Permissions feature allows companies to create custom roles and define what each user can access within the organization.</p><p>This helps ensure that each user only has access to the features relevant to their responsibilities.</p><h3 id="steps-to-create-a-role" tabindex="-1">Steps to Create a Role <a class="header-anchor" href="#steps-to-create-a-role" aria-label="Permalink to &quot;Steps to Create a Role&quot;">​</a></h3><p><strong>Step: 1</strong> Go to My <strong>Account → Profile → Roles</strong> from the company storefront.</p><p>The <strong>Company Roles</strong> page will appear, showing all existing roles with options to search, filter, or manage them.</p><p>As shown in the image below, you can view the list of existing roles, such as “Administrator”.</p>',7)),n(t,{src:"/images/b2b-ecommerce-platform/role-1.png",alt:"Super Admin Login"}),e[1]||(e[1]=o("<p><strong>Step: 2</strong> Click on Add Role to open the Add Company Role form.</p><p><strong>Step: 3</strong> Fill in the following details:</p><p><strong>A) Name –</strong> Enter the name of the role (e.g., Administrator, Manager, Purchaser).</p><p><strong>B) Description –</strong> Add a short description to specify the purpose of the role.</p><p><strong>Step: 4</strong> Under Access Control, choose the level of access you want to assign:</p><p><strong>A) All Permissions –</strong> Grants complete access to all available company features.</p><p><strong>B) Custom Permissions –</strong> Allows you to manually select specific permissions for the role based on your company’s needs.</p><p><strong>Step: 5</strong> Once you have configured the access control settings, click Save Role to create the new role. As shown in the image below,</p>",8)),n(t,{src:"/images/b2b-ecommerce-platform/role-2.png",alt:"Super Admin Login"}),e[2]||(e[2]=o('<p><strong>Note:</strong></p><ul><li><p>You can edit or delete existing roles anytime from the same page.</p></li><li><p>Once a role is created, it can be assigned to users while adding or editing a company user.</p></li></ul><h3 id="company-user-management" tabindex="-1">Company User Management <a class="header-anchor" href="#company-user-management" aria-label="Permalink to &quot;Company User Management&quot;">​</a></h3><p>The Company User Management feature allows companies to add and manage multiple users under their account.</p><p>Each user can have a defined role and access level, helping businesses maintain proper control within their organization.</p><h4 id="steps-to-add-a-new-company-user" tabindex="-1">Steps to Add a New Company User <a class="header-anchor" href="#steps-to-add-a-new-company-user" aria-label="Permalink to &quot;Steps to Add a New Company User&quot;">​</a></h4><p><strong>Step: 1</strong> Go to My Account →Profile → Users from the company storefront.</p><p><strong>Step: 2</strong> The Company Users page will appear, showing all existing users with options to search, filter, or manage them.</p><p>As shown in the image below, the list will appear empty initially if no users are created.</p><p>The Company Users page offers two ways to add members:</p><ul><li><strong>Add User –</strong> Create a brand-new company user from scratch.</li><li><strong>Invite User –</strong> Invite a customer who already has an account on the store to join your company.</li></ul>',11)),n(t,{src:"/images/b2b-ecommerce-platform/role-3.png",alt:"Super Admin Login"}),e[3]||(e[3]=o("<p><strong>Step: 3</strong> Click on Add User to open the Add Company User form.</p><p><strong>Step: 4</strong> Fill in the following details:</p><p><em>A) First Name –</em> Enter the user’s first name.</p><p><em>B) Last Name –</em> Enter the user’s last name.</p><p><em>C) Email –</em> Enter a valid email address.</p><p><em>D) Phone –</em> Provide the user’s contact number.</p><p><em>E) Gender –</em> Select the user’s gender.</p><p><em>F) Date of Birth –</em> Enter the user’s date of birth.</p><p><em>G) Role –</em> Choose the appropriate role from the list of created roles.</p><p><em>H) Status –</em> Set the user’s account as Active or Inactive.</p><p><em>I) Is Suspended –</em> If enabled, the user can log in but cannot proceed to checkout. A message will display: “Your account has been suspended.”</p><p><strong>Step: 5</strong> Optionally, upload a <strong>Profile Image or Video</strong> for the user.</p><p><strong>Step: 6</strong> After filling in all required information, click <strong>Save User</strong> to add the new company user. As shown in the image below.</p>",13)),n(t,{src:"/images/b2b-ecommerce-platform/role-4.png",alt:"Super Admin Login"}),e[4]||(e[4]=o('<p><strong>Note:</strong></p><p>Company administrators can edit, suspend, or delete users at any time.</p><p>Access to features depends on the role permissions assigned to each user.</p><h3 id="invite-an-existing-user" tabindex="-1">Invite an Existing User <a class="header-anchor" href="#invite-an-existing-user" aria-label="Permalink to &quot;Invite an Existing User&quot;">​</a></h3><p>Instead of creating a new user, you can invite a customer who already has an account on the store to join your company.</p><p><strong>Step: 1</strong> On the <strong>Company Users</strong> page, click <strong>Invite User</strong>.</p><p><strong>Step: 2</strong> Fill in the invitation details:</p><p><strong>A) Customer Email –</strong> Enter the email address of the existing customer you want to invite.</p><p><strong>B) Role –</strong> Choose the role the invited user will have once they join.</p><p><strong>Step: 3</strong> Click <strong>Send Invitation</strong>. The customer receives an email and becomes a company user once they accept.</p>',10)),n(t,{src:"/images/b2b-ecommerce-platform/role-5.png",alt:"Invite Existing User"}),e[5]||(e[5]=s("h4",{id:"pending-invitations",tabindex:"-1"},[a("Pending Invitations "),s("a",{class:"header-anchor",href:"#pending-invitations","aria-label":'Permalink to "Pending Invitations"'},"​")],-1)),e[6]||(e[6]=s("p",null,[a("Invitations that have been sent but not yet accepted appear in the "),s("strong",null,"Pending Invitations"),a(" list, showing the email, role, the date invited, and the expiry date. You can "),s("strong",null,"Revoke"),a(" a pending invitation at any time.")],-1)),n(t,{src:"/images/b2b-ecommerce-platform/role-6.png",alt:"Pending Invitations"}),e[7]||(e[7]=o('<blockquote><p><strong>Note:</strong> A customer can only be invited if they are not already a member of another company.</p></blockquote><h3 id="accepting-an-invitation" tabindex="-1">Accepting an Invitation <a class="header-anchor" href="#accepting-an-invitation" aria-label="Permalink to &quot;Accepting an Invitation&quot;">​</a></h3><p>When a customer is invited, they receive an email with a <strong>View Invitation</strong> link. After signing in with the invited email address, they see the <strong>Company Invitation</strong> page showing which company and role they have been invited to.</p><p>They can then <strong>Accept Invitation</strong> to join the company as a member, or <strong>Decline</strong> the invitation.</p><blockquote><p><strong>Note:</strong> The <strong>Messages</strong> permission separately controls whether a company user can view and participate in quotation / purchase order message threads.</p></blockquote>',5))])}const b=r(m,[["render",c]]);export{y as __pageData,b as default};
